class Solution:
    def canTransform(self, start: str, result: str) -> bool:
        if start.count('X') != result.count('X'):
            return False

        s = []
        for char in start:
            if char == 'X':
                continue
            s.append(char)

        r = []
        for char in result:
            if char == 'X':
                continue
            r.append(char)

        if len(s) != len(r):
            return False

        for i in range(len(s)):
            if s[i] != r[len(s) - 1 - i]:
                return False

        return True
```
